      .init_busy_o(init_busy[bank]),
      .flash_power_ready_h_i,
      .flash_power_down_h_i
    );
  end

  lc_ctrl_pkg::lc_tx_t unused_scanmode;
  logic unused_scan_en;
  logic unused_scan_rst_n;
